// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface ICourseAllocation {
    function addressToTeacherId(
        address teacher
    ) external view returns (uint256);

    function setCourseProperties(
        uint256 courseId,
        uint256 importance,
        bool suitable
    ) external;
}

contract CourseVoting {
    struct Proposal {
        uint256 courseId;
        string courseName;
        uint256 totalScore;
        uint256 voteCount;
        uint256 agreeCount;
        uint256 disagreeCount;
        bool finalized;
        mapping(address => bool) hasVoted;
    }

    address public owner;
    ICourseAllocation public courseAllocation;

    mapping(uint256 => Proposal) public proposals;
    uint256 public proposalCount;

    event ProposalCreated(
        uint256 proposalId,
        uint256 courseId,
        string courseName
    );
    event VoteCast(
        uint256 proposalId,
        address teacher,
        uint256 score,
        bool suitable
    );
    event ProposalFinalized(
        uint256 proposalId,
        uint256 averageScore,
        bool suitable
    );

    modifier onlyTeacher() {
        require(
            courseAllocation.addressToTeacherId(msg.sender) != 0,
            "Only teachers allowed"
        );
        _;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    constructor(address _courseAllocationAddress) {
        owner = msg.sender;
        courseAllocation = ICourseAllocation(_courseAllocationAddress);
    }

    function createProposal(
        uint256 _courseId,
        string memory _courseName
    ) public onlyOwner returns (uint256) {
        proposalCount++;
        Proposal storage proposal = proposals[proposalCount];
        proposal.courseId = _courseId;
        proposal.courseName = _courseName;
        emit ProposalCreated(proposalCount, _courseId, _courseName);
        return proposalCount;
    }

    function vote(
        uint256 _proposalId,
        uint256 _score,
        bool _suitable
    ) public onlyTeacher {
        Proposal storage proposal = proposals[_proposalId];
        require(!proposal.finalized, "Proposal already finalized");
        require(!proposal.hasVoted[msg.sender], "Already voted");
        require(_score >= 1 && _score <= 10, "Invalid score");

        proposal.hasVoted[msg.sender] = true;
        proposal.totalScore += _score;
        proposal.voteCount++;

        if (_suitable) {
            proposal.agreeCount++;
        } else {
            proposal.disagreeCount++;
        }

        emit VoteCast(_proposalId, msg.sender, _score, _suitable);
    }

    function finalizeProposal(uint256 _proposalId) public onlyOwner {
        Proposal storage proposal = proposals[_proposalId];
        require(!proposal.finalized, "Already finalized");
        require(proposal.voteCount > 0, "No votes cast");

        proposal.finalized = true;
        uint256 averageScore = proposal.totalScore / proposal.voteCount;
        bool suitable = proposal.agreeCount > proposal.disagreeCount;

        courseAllocation.setCourseProperties(
            proposal.courseId,
            averageScore,
            suitable
        );

        emit ProposalFinalized(_proposalId, averageScore, suitable);
    }

    function getProposalResults(
        uint256 _proposalId
    ) public view returns (uint256 averageScore, bool suitable) {
        Proposal storage proposal = proposals[_proposalId];
        require(proposal.finalized, "Not finalized yet");
        averageScore = proposal.totalScore / proposal.voteCount;
        suitable = proposal.agreeCount > proposal.disagreeCount;
    }
}
